var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"세계는 마치 신이 인류의 자격을 시험하듯 끊임없이 재난을 만들어내지.","JPN":"世界はまるで神が人類の資格を試すかのように、絶えず災害を生み出す。","ENG":"The world keeps birthing disasters, almost like a test from the gods to see if humanity deserves to survive.","TWN":"世界彷彿在考驗人類的資格，不斷地製造災難。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 때론, 인류에게 시련을 주기 위해 태어난 재난들이 서로를 잡아먹기도 한다네.","JPN":"時には人類に試練を与えるために生まれた災害同士が、互いを食らいつくすこともある。","ENG":"And sometimes, those disasters meant to test us start devouring each other.","TWN":"有時，為了給人類帶來考驗而誕生的災難，也會互相吞噬。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 자기들끼리 먹고 먹혀 소멸했다면 좋았겠지만… 그것들은 불사의 몸을 가진 탓에 서로를 먹어치우며 끊임없이 커져버리고 말았어.","JPN":"そうやって互いに食らい合って消滅したら良かったのだが……それらは不死の体を持つがために、食らうことで際限なく大きくなってしまった。","ENG":"If only they had eaten each other into extinction… But they couldn't. Their bodies are immortal, so they just kept growing.","TWN":"如果牠們能這樣互相吞噬而消亡就好了… 但牠們擁有不死之身，互相吞噬後反而會不斷壯大。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그 재난이란 게… 바로 관리국이 말하는 세 짐승인가?","JPN":"その災害とは……管理局でいう3匹のケモノのことか？","ENG":"Are you saying these disasters… are what the Administration calls the Three Beasts?","TWN":"你說的災難… 就是管理局所說的三隻野獸嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Exactly.","TWN":"沒錯。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"세 짐승의 머리가 커질대로 커져 지성이 생겼을 때쯤엔 자신들의 끊임없는 결핍을 달래줄 유일한 수단이 인간이란 걸 알게 됐지.","JPN":"3匹のケモノがだんだん成長し、知性を持ち始めた頃……やつらは自分たちの果てしない飢えを満たせる唯一の存在が、人間だということを知った。","ENG":"When the Three Beasts' grew enough power to gain an intelligence of their own, they figured out that the only thing that could satisfy their bottomless hunger was humanity.","TWN":"當三隻野獸的頭顱越來越大，產生了智慧後，牠們意識到唯一能填補牠們無盡空缺的方法，就是人類。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"짐승들은 인간을 잡아먹기 시작했고, 그 결핍을 채우면 채울수록 놈들은 단순한 재난이 아닌 완성된 존재로 거듭나기 시작했다네.","JPN":"ケモノたちは人間を食らうようになり、飢えを満たせば満たせるほど、やつらは単なる災害ではなく完成した存在へと変貌を遂げ始めた。","ENG":"The Beasts started consuming humans. And the more they fed, the less they remained disasters and the more they became something complete.","TWN":"野獸開始吞噬人類，而牠們越是填補空缺，就越是從單純的災難，蛻變為完整的存在。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"짐승들이 완성된 존재가 된다는 건… 어떤 의미요?","JPN":"ケモノが完成した存在になるとは、どういう意味だ？","ENG":"Complete…? What do you mean?","TWN":"野獸成為完整的存在… 是什麼意思？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"세계와 운명이란 고리로 엮여 하나가 되는 것.","JPN":"運命という輪で世界と繋がり一つになること。","ENG":"Becoming one with the world by intertwining with fate itself.","TWN":"與世界和命運連結為一。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우린 그런 존재를 마왕이라 정의한다네.","JPN":"我々はそのような存在を「魔王」と定義している。","ENG":"We call that kind of being… a Demon Lord.","TWN":"我們將這種存在，定義為魔王。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그러고보니 동월은… 15일도 남지 않았다는 말을 했었소.","JPN":"そういえば先程トウゲツは……あと15日もないと言っていた。","ENG":"Come to think of it, Dongwol said… that we don't even have fifteen days left.","TWN":"話說佟月… 說只剩下15天了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그렇담 그 15일이란 건…?","JPN":"ということは、その15日とは……？","ENG":"Then that fifteen days mean…?","TWN":"那麼那15天…？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"범이 마왕으로 거듭나기까지 남은 시간일세.","JPN":"虎が魔王になるまでの残り時間だ。","ENG":"That's the time left until the Tiger becomes a Demon Lord.","TWN":"是老虎蛻變為魔王，剩下的時間。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"세상이 마왕의 일부가 되고, 마왕이 세상의 일부가 되어… 설령 기적이 일어나 마왕을 처단해도, 그 순간 세상은 종말을 맞게 되겠지.","JPN":"世界が魔王の一部となり、魔王は世界の一部となり……たとえ奇跡が起きて魔王を倒すことができても、その瞬間世界は終末を迎えるだろう。","ENG":"Once that happens, the world becomes a part of the Demon Lord's as it becomes part of the world. And even if a miracle occurs and we manage to kill it, the world would end the moment we do.","TWN":"世界成為魔王的一部分，魔王成為世界的一部分… 就算發生奇蹟將魔王斬殺，那瞬間世界也會迎來末日。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"앞서 말했다시피, 우린 그걸 막기 위한 대책을 오랫동안 준비해왔다네.","JPN":"さっきも言ったように、我々は長い間、それを阻止するための対策を講じてきたんだ。","ENG":"That's why we've been preparing all this time to stop it.","TWN":"就像我之前說的，我們為了阻止那件事，準備了很長時間的應對措施。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 그 대책엔 자네의 도움이 반드시 필요한 동시에…","JPN":"そしてその対策を実行するためには、君の助けが必要で……","ENG":"And for that, we need your help…","TWN":"而那個應對措施，必須要有你的幫助…"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…걱정마시오.","JPN":"……心配はいらん。","ENG":"…No need to worry.","TWN":"…別擔心。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"작전의 개요와 그 <color=#ffd34c>위험성</color>에 대해선 이미 충분히 이해했으니.","JPN":"作戦の概要とその<color=#ffd34c>危険性</color>については、十分理解した。","ENG":"I understand exactly what's at stake and what kind of <color=#ffd34c>danger</color> this mission carries.","TWN":"關於作戰的概要和<color=#ffd34c>危險性</color>，我已經完全理解了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"작전 준비가 끝나면 다시 호출하겠네.","JPN":"作戦準備が終わったらまた呼ぼう。","ENG":"We'll call you when everything's ready.","TWN":"等作戰準備就緒，我會再次呼叫你。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"숙소로 안내해줄 테니, 잠시 눈이라도 붙이고 있게나.","JPN":"宿に案内する。しばらく仮眠でもとってくれ。","ENG":"In the meantime, get some rest. I'll have someone show you to your quarters.","TWN":"我會帶你去宿舍，你先休息一下。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"PRISON_SPACE","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"여전히 처음부터 끝까지 글귀라곤 하나도 보이지 않는군.","JPN":"相変わらず最初から最後まで、文字の一つも見当たらんな。","ENG":"Still nothing. Not a single letter left in this book.","TWN":"那本書依然從頭到尾都看不到任何文字。"},"stage":{"bg":"PRISON_SPACE","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"멀쩡했던 글귀가 사라질 이유라면, 그것은 분명 정보 오염의 영향일 터…","JPN":"確かにあった文字が消えたとすれば、それは情報汚染の影響のはず………","ENG":"If the text disappeared, it must've been due to the data corruption…","TWN":"本來好好的文字會消失，那肯定是資訊污染的影響…"},"stage":{"bg":"PRISON_SPACE","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"명달 대장이 그 점을 간과했을 리는 없다.","JPN":"アカタツ隊長がそれを見落としていたとは思えない。","ENG":"No way Commander Myeongdal would've overlooked that.","TWN":"明達隊長不可能忽略這一點。"},"stage":{"bg":"PRISON_SPACE","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"PRISON_SPACE","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"천재란 녀석이 하나부터 열까지 설명해줘야 알겠더냐?","JPN":"天才ともあろうものが、いちいち説明しないと分からないのか？","ENG":"You need someone to spell it all out for you, genius?","TWN":"你這傢伙是天才，難道每件事都要我從頭到尾解釋給你聽嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"늘 하던 대로, 피땀 흘려 재주껏 알아내야지.","JPN":"いつも通り、血と汗を流し、使えるものはすべて使って見つけ出せ。","ENG":"Figure it out like you always do. Bleed, sweat, and earn it.","TWN":"像以前一樣，靠著血汗和你的本事自己找出來。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};